const newsletter = $("Buscar Newsletter (Supabase)").first().json[0];
const content = newsletter.content_json || {};
const world = newsletter.world || "tech";

// === ENGINE CAMALEÃO (THEMES) — Sincronizado com world.dart ===
const THEMES = {
  "tech": {
    primaryColor: "#22C55E",
    headerTitle: "FRESH NEWS",
    headerSub: "Protocolo de Inteligência Técnica",
    quickTakesTitle: "⚡ GIRO TECH",
    footerSignOff: "Deslogando do Terminal...",
    bgColor: "#050505",
    containerBg: "#0d0d0d",
    borderColor: "rgba(34, 197, 94, 0.2)",
    mutedColor: "#b9cacb",
    badgeBg: "rgba(34, 197, 94, 0.1)",
    waIcon: "🟢"
  },
  "game": {
    primaryColor: "#A855F7",
    headerTitle: "FRESH NEWS",
    headerSub: "Player One Ready",
    quickTakesTitle: "🕹️ PRESS START",
    footerSignOff: "Salvando o progresso... Game Over.",
    bgColor: "#040008",
    containerBg: "#0a0012",
    borderColor: "rgba(168, 85, 247, 0.2)",
    mutedColor: "#d8c8e0",
    badgeBg: "rgba(168, 85, 247, 0.1)",
    waIcon: "🟣"
  },
  "music": {
    primaryColor: "#EAB308",
    headerTitle: "FRESH NEWS",
    headerSub: "Sintonizado na Frequência",
    quickTakesTitle: "🎵 SETLIST RÁPIDO",
    footerSignOff: "Desligando os amplificadores... Fim da faixa.",
    bgColor: "#080600",
    containerBg: "#120e00",
    borderColor: "rgba(234, 179, 8, 0.2)",
    mutedColor: "#e0d5c8",
    badgeBg: "rgba(234, 179, 8, 0.1)",
    waIcon: "🟡"
  },
  "gear": {
    primaryColor: "#EF4444",
    headerTitle: "FRESH NEWS",
    headerSub: "Engenharia e Maquinário",
    quickTakesTitle: "⚙️ DIAGNÓSTICO",
    footerSignOff: "Desligando as máquinas... Sistema em repouso.",
    bgColor: "#080000",
    containerBg: "#120000",
    borderColor: "rgba(239, 68, 68, 0.2)",
    mutedColor: "#e0c8c8",
    badgeBg: "rgba(239, 68, 68, 0.1)",
    waIcon: "🔴"
  }
};

const theme = THEMES[world] || THEMES["tech"];
const editionPadded = (newsletter.edition_number || 1).toString().padStart(3, '0');
const year = new Date().getFullYear();

// === GERAÇÃO DO HTML ESTILIZADO (E-MAIL) ===
let html = `
<div style="background-color: ${theme.bgColor}; padding: 20px 0; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Ubuntu, sans-serif;">
  <div style="background-color: ${theme.containerBg}; margin: 0 auto; padding: 0; max-width: 640px; border: 1px solid ${theme.borderColor}; border-radius: 16px; overflow: hidden;">

    <!-- Header -->
    <div style="padding: 40px 20px; text-align: center; position: relative;">
      <span style="display: inline-block; padding: 4px 12px; border-radius: 12px; font-size: 12px; font-weight: bold; letter-spacing: 2px; margin-bottom: 16px; color: ${theme.primaryColor}; background-color: ${theme.badgeBg};">
        ED. ${editionPadded}
      </span>
      <h1 style="font-size: 36px; font-weight: 900; margin: 0; letter-spacing: -1px; text-transform: uppercase; color: ${theme.primaryColor}; font-family: 'Outfit', -apple-system, sans-serif;">
        ${theme.headerTitle}
      </h1>
      <p style="font-size: 11px; margin: 12px 0 0; text-transform: uppercase; letter-spacing: 4px; font-weight: 800; color: ${theme.primaryColor};">
        ${theme.headerSub}
      </p>
    </div>

    <!-- Content Intro -->
    <div style="padding: 0 40px 40px;">
      <h2 style="color: #ffffff; font-size: 28px; font-weight: 800; line-height: 1.3; margin: 0 0 20px; letter-spacing: -0.5px;">
        ${newsletter.title || ""}
      </h2>

      <!-- Box Summary Intro -->
      <div style="padding: 20px; border-left: 4px solid ${theme.primaryColor}; background-color: ${theme.badgeBg}; margin-bottom: 35px; border-radius: 0 8px 8px 0;">
        <p style="font-size: 17px; line-height: 26px; margin: 0; font-style: italic; color: ${theme.mutedColor};">
          ${newsletter.summary_intro || ""}
        </p>
      </div>
`;

// === QUICK TAKES ===
if (content.quickTakes && content.quickTakes.length > 0) {
  html += `
      <div style="border: 2px solid ${theme.borderColor}; padding: 24px; margin-bottom: 30px; border-radius: 8px; background-color: ${theme.bgColor};">
        <h3 style="font-size: 16px; font-weight: 900; margin: 0 0 15px 0; text-transform: uppercase; letter-spacing: 1px; color: ${theme.primaryColor};">
          ${theme.quickTakesTitle}
        </h3>
        <ul style="margin: 0; padding: 0; list-style-type: none;">
  `;
  content.quickTakes.forEach(take => {
    html += `
          <li style="font-size: 15px; line-height: 24px; margin-bottom: 12px; font-weight: 500; color: ${theme.mutedColor};">
            <span style="color: ${theme.primaryColor}; margin-right: 8px;">■</span>${take}
          </li>
    `;
  });
  html += `
        </ul>
      </div>
  `;
}

html += `
      <hr style="margin: 40px 0; border: 0; border-top: 1px dashed ${theme.borderColor};" />
`;

// === CATEGORIES / ITENS ===
if (content.categories && content.categories.length > 0) {
  content.categories.forEach(cat => {
    html += `
      <div style="margin-bottom: 50px;">
        <div style="border-bottom: 2px solid ${theme.primaryColor}; margin-bottom: 25px; padding-bottom: 8px;">
          <h3 style="font-size: 18px; font-weight: 900; text-transform: uppercase; letter-spacing: 2px; margin: 0; color: ${theme.primaryColor};">
            ${cat.name}
          </h3>
        </div>
    `;

    cat.items.forEach((item, index) => {
      html += `
        <div style="margin-bottom: 35px; padding-left: 16px; border-left: 2px solid ${theme.primaryColor};">
      `;

      // Imagem opcional
      if (item.imageUrl) {
        html += `
          <a href="${item.link || '#'}" style="text-decoration: none;">
            <img src="${item.imageUrl}" alt="${item.headline}" style="border-radius: 8px; margin-bottom: 16px; border: 1px solid rgba(255, 255, 255, 0.1); width: 100%; max-width: 560px; object-fit: cover;" />
          </a>
        `;
      }

      html += `
          <a href="${item.link || '#'}" style="text-decoration: none; color: inherit;">
            <h4 style="color: #ffffff; font-size: 22px; font-weight: bold; line-height: 1.4; margin-top: 0; margin-bottom: 12px;">
              ${item.headline}
            </h4>
          </a>
          <p style="font-size: 16px; line-height: 1.6; margin: 0 0 16px; color: ${theme.mutedColor};">
            ${item.story}
          </p>
          <a href="${item.link || '#'}" style="font-size: 14px; text-decoration: none; font-weight: bold; text-transform: uppercase; letter-spacing: 1px; color: ${theme.primaryColor};">
            Ler fonte original &rarr;
          </a>
      `;

      // Separador entre itens (exceto no último)
      if (index < cat.items.length - 1) {
        html += `
          <div style="height: 1px; margin: 25px 0; background-color: ${theme.borderColor};"></div>
        `;
      }

      html += `
        </div>
      `;
    });

    html += `
      </div>
    `;
  });
}

// === FOOTER ===
html += `
      <!-- Footer -->
      <div style="padding: 40px; text-align: center; margin-top: 50px; border-top: 2px solid ${theme.borderColor}; background-color: ${theme.bgColor}; margin-left: -40px; margin-right: -40px; margin-bottom: -40px;">
        <p style="font-size: 14px; font-weight: bold; text-transform: uppercase; letter-spacing: 2px; margin-top: 0; margin-bottom: 20px; color: ${theme.primaryColor};">
          ${theme.footerSignOff}
        </p>
        <p style="color: #919191; font-size: 12px; line-height: 20px; text-transform: uppercase; letter-spacing: 1px; margin: 0;">
          © ${year} Fresh News. Multiverse Edition.<br/>
          <a href="{{ unsubscribe_url }}" style="text-decoration: underline; font-weight: normal; margin-top: 10px; display: inline-block; color: ${theme.mutedColor};">Unsubscribe</a>
        </p>
      </div>

    </div> <!-- Fecha Content Intro -->
  </div> <!-- Fecha ContainerBg -->
</div> <!-- Fecha BgColor -->
`;

// === GERAÇÃO DO MARKDOWN (WHATSAPP) ===
let whatsapp = `*=== ED. #${editionPadded} | ${world.toUpperCase()} ===*\n\n`;
whatsapp += `*${newsletter.title}*\n_${newsletter.summary_intro}_\n\n`;

if (content.quickTakes && content.quickTakes.length > 0) {
  whatsapp += `\`\`\`> ${theme.quickTakesTitle}\`\`\`\n`;
  content.quickTakes.forEach(take => {
    whatsapp += `${theme.waIcon} ${take}\n`; // Ícone muda conforme o mundo
  });
  whatsapp += `\n`;
}

if (content.categories && content.categories.length > 0) {
  content.categories.forEach(cat => {
    whatsapp += `\`\`\`[ ${cat.name} ]\`\`\`\n\n`;
    cat.items.forEach(item => {
      whatsapp += `*${item.headline}*\n${item.story}\n\n`;
    });
  });
}

// Fechamento WhatsApp Dinâmico
whatsapp += `\`\`\`${theme.footerSignOff}\`\`\``;

// === RETORNO N8N ===
return {
  html_email: html,
  whatsapp_message: whatsapp
};
